import React, { Component } from 'react';
import * as d3 from 'd3'
import { scaleOrdinal } from 'd3';

class cirlce extends Component {
  state = {
    data: [
      { name: '全世界', parent: '' },

      { name: '亚洲', parent: '全世界' },
      { name: '欧洲', parent: '全世界' },
      { name: '非洲', parent: '全世界' },
      { name: '美洲', parent: '全世界' },
      { name: '大洋洲', parent: '全世界' },

      { name: '中国', parent: '亚洲', people: 14 },
      { name: '印度', parent: '亚洲', people: 13.5 },
      { name: '印度尼西亚', parent: '亚洲', people: 2.66 },
      { name: '巴基斯坦', parent: '亚洲', people: 2.00 },
      { name: '孟加拉国', parent: '亚洲', people: 1.66 },
      { name: '日本', parent: '亚洲', people: 1.27 },

      { name: '俄罗斯', parent: '欧洲', people: 1.43 },
      { name: '德国', parent: '欧洲', people: 0.822 },
      { name: '英国', parent: '欧洲', people: 0.666 },
      { name: '法国', parent: '欧洲', people: 0.652 },
      { name: '意大利', parent: '欧洲', people: 0.604 },
      { name: '西班牙', parent: '欧洲', people: 0.463 },

      { name: '尼日尼亚', parent: '非洲', people: 1.70 },
      { name: '埃及', parent: '非洲', people: 0.92 },
      { name: '埃塞俄比亚', parent: '非洲', people: 0.91 },
      { name: '刚果', parent: '非洲', people: 0.73 },
      { name: '南非', parent: '非洲', people: 0.51 },
      { name: '坦桑尼亚', parent: '非洲', people: 0.43 },

      { name: '美国', parent: '美洲', people: 3.26 },
      { name: '墨西哥', parent: '美洲', people: 1.30 },
      { name: '加拿大', parent: '美洲', people: 0.37 },
      { name: '危地马拉', parent: '美洲', people: 0.17 },
      { name: '海地', parent: '美洲', people: 0.11 },
      { name: '哥斯达黎加', parent: '美洲', people: 0.05 },

      { name: '澳大利亚', parent: '大洋洲', people: 0.25 },
      { name: '巴布亚新几内亚', parent: '大洋洲', people: 0.08 },
      { name: '新西兰', parent: '大洋洲', people: 0.04 },
      { name: '斐济', parent: '大洋洲', people: 0.008 },
      { name: '所罗门群岛', parent: '大洋洲', people: 0.007 },
      { name: '瓦努阿图', parent: '大洋洲', people: 0.003 },
    ]
  }
  render() {
    return (
      <div>
        <svg className="zwc"></svg>
      </div>
    );
  }
  componentDidMount() {
    const width = 1026
    const height = 600
    const style = '1px dashed #ccc'

    const margin = {
      top: 30,
      right: 30,
      bottom: 50,
      left: 50
    }

    const innerWidth = width - margin.left - margin.right
    const innerHeight = height - margin.top - margin.bottom

    const svg = d3.select('.zwc')
      .attr('width', width)
      .attr('height', height)
      .style('border', style)
    
    const group = svg.append('g')
      .attr('width', innerWidth)
      .attr('height', innerHeight)
      .attr('transform', `translate(${margin.left}, ${margin.top})`)
    
    const stratify = d3.stratify()
      .id(d => d.name)
      .parentId(d => d.parent)
    
    const rootNode = stratify(this.state.data)
      .sum(d => d.people)
    
    const pack = d3.pack()
      .size([innerWidth, innerHeight])
      .padding(5)
    
    const bubbleData = pack(rootNode).descendants()

    const nodes = group.selectAll('g')
      .data(bubbleData)
      .enter()
      .append('g')
      .attr('transform', d => `translate(${d.x}, ${d.y})`)

    const color = scaleOrdinal(['pink', 'orange', 'red'])

    nodes.append('circle')
      .attr('r', d => d.r)
      .attr('stroke', '#fff')
      .attr('stroke-width', 2)
      .attr('fill', d => color(d.depth))
    
    nodes.filter(d => !d.children)
      .append('text')
      .text(d => d.data.name)
      .attr('text-anchor', 'middle')
      .attr('fill', '#fff')
      .attr('font-size', d => d.value * 5)
      .attr('dy', '0.4em')
    
    group.append('text')
      .text('世界五大洲人口所占比例图')
      .attr('font-size', '1.5em')
      .attr('fill', 'steelblue')
  }
}

export default cirlce;