import React, { Component } from 'react';
import * as d3 from 'd3'

class arc extends Component {
  state = {
    data: [
      { name: '亚洲', area: 4400 },
      { name: '欧洲', area: 1016 },
      { name: '非洲', area: 3020 },
      { name: '美洲', area: 4200 },
      { name: '大洋洲', area: 897 },
    ]
  }
  render() {
    return (
      <div>
        <svg className="zwc"></svg>
      </div>
    );
  }
  componentDidMount() {
    const width = 1026
    const height = 600
    const style = '1px dashed #ccc'

    const margin = {
      top: 30,
      right: 30,
      bottom: 50,
      left: 50
    }

    const innerWidth = width - margin.left - margin.right
    const innerHeight = height - margin.top - margin.bottom

    const svg = d3.select('.zwc')
      .attr('width', width)
      .attr('height', height)
      .style('border', style)
    
    const group = svg.append('g')
      .attr('width', innerWidth)
      .attr('height', innerHeight)
      .attr('transform', `translate(413, 300)`)
    
    const update = data => {
      const arcTweenEnter = d => {
        let i = d3.interpolate(d.endAngle, d.startAngle)
        return function(t) {
          d.startAngle = i(t)
          return arcPath(d)
        }
      }

      const arcTweenExit = d => {
        let i = d3.interpolate(d.startAngle, d.endAngle)
        return function(t) {
          d.startAngle = i(t)
          return arcPath(d)
        }
      }
      function arcTweenUpdate(d) {
        let i = d3.interpolate(this._current, d)
        this._current = i(1)
        return function(t) {
          return arcPath(i(t))
        }
      }
      const arcPath = d3.arc()
        .outerRadius(innerHeight / 2)
        .innerRadius(innerHeight / 4)
      
      const piePath = d3.pie()
        .value(d => d.area)
        .sort(null)
      
      const paths = group.selectAll('path')
        .data(piePath(data))
      
      const color = d3.scaleOrdinal()
        .domain(data.map(d => d.name))
        .range(['yellow', 'steelblue', 'black', 'red', 'green', 'purple', 'orange'])
      
      // console.log(data.map(d => d.name))
      // console.log(color('欧洲'))
      
      paths.exit()
        .transition()
        .duration(1000)
        .attrTween('d', arcTweenExit)
        .remove()
      
      paths.attr('d', arcPath)
        .transition()
        .duration(1000)
        .attrTween('d', arcTweenUpdate)
      
      paths.enter()
        .append('path')
        .attr('d', arcPath)
        .attr('stroke', '#fff')
        .attr('stroke-width', 4)
        .attr('fill', d => color(d.data.name))
        .each(function(d) { this._current = d })
        .transition()
        .duration(1000)
        .attrTween('d', arcTweenEnter)
      
      group.selectAll('path')
        .on('mouseenter', (e, data) => {
          // console.log(e.currentTarget)
          d3.select(e.currentTarget)
            .style('opacity', '0.5')
            .style('cursor', 'pointer')
        })
        .on('mouseleave', (e, data) => {
          d3.select(e.currentTarget)
            .style('opacity', '1')
            // .attrTween('d', arcTweenEnter)
        })
      
      let sum = d3.sum(data.map(d => d.area))

      const arcTexts = group.selectAll('.text')
        .data(piePath(data))
      
      arcTexts.exit()
        .remove()
      
      arcTexts.attr('transform', d => `translate(${arcPath.centroid(d)})`)
        .attr('text-anchor', 'middle')
        .text(d => (((d.data.area) / sum) * 100).toFixed(0) + '%')
        .attr('fill', '#fff')
      
      arcTexts.enter()
        .append('text')
        .attr('class', 'text')
        .attr('transform', d => `translate(${arcPath.centroid(d)})`)
        .attr('text-anchor', 'middle')
        .text(d => (((d.data.area) / sum) * 100).toFixed(0) + '%')
        .attr('fill', '#ccc')
      
      const rects = group.selectAll('.color')
        .data(piePath(data))

      rects.exit()
        .remove()

      rects.attr('width', 30)
        .attr('height', 20)
        .attr('x', 413)
        .attr('y', (d, i) => i * 30 - 250)
        .attr('fill', d => color(d.data.name))

      rects.enter()
        .append('rect')
        .attr('class', 'color')
        .attr('width', 30)
        .attr('height', 20)
        .attr('x', 413)
        .attr('y', (d, i) => i * 30 - 250)
        .attr('fill', d => color(d.data.name))
      
      const texts = group.selectAll('.introduction')
        .data(piePath(data))

      texts.exit()
        .remove()

      texts.style('display', 'inline-block')
        .text(d => d.data.name)
        .attr('x', 450)
        .attr('y', (d, i) => i * 30 - 236)
        .attr('width', 20)
        .attr('height', 10)
        .attr('font-size', '0.8em')

      texts.enter()
        .append('text')
        .attr('class', 'introduction')
        .style('display', 'inline-block')
        .text(d => d.data.name)
        .attr('x', 450)
        .attr('y', (d, i) => i * 30 - 236)
        .attr('width', 20)
        .attr('height', 10)
        .attr('font-size', '0.8em')
      
      group.append('text')
        .text('世界五大洲面积所占比例')
        .attr('font-size', '1.5em')
        .attr('transform', `translate(-380, -250)`)
    }
    update(this.state.data)
  }
}

export default arc;