import React, { Component } from 'react';
import * as d3 from 'd3'

class tree extends Component {
  state = {
    data: [
      { name: '江浙沪', parent: '' },

      { name: '江苏省', parent: '江浙沪' },
      { name: '浙江省', parent: '江浙沪' },
      { name: '上海市', parent: '江浙沪' },

      { name: '南京', parent: '江苏省' },
      { name: '无锡', parent: '江苏省' },
      { name: '徐州', parent: '江苏省' },
      { name: '常州', parent: '江苏省' },
      { name: '苏州', parent: '江苏省' },
      { name: '南通', parent: '江苏省' },
      { name: '连云港', parent: '江苏省' },
      { name: '淮安', parent: '江苏省' },
      { name: '盐城', parent: '江苏省' },
      { name: '扬州', parent: '江苏省' },
      { name: '镇江', parent: '江苏省' },
      { name: '泰州', parent: '江苏省' },
      { name: '宿迁', parent: '江苏省' },

      { name: '杭州', parent: '浙江省' },
      { name: '宁波', parent: '浙江省' },
      { name: '温州', parent: '浙江省' },
      { name: '绍兴', parent: '浙江省' },
      { name: '湖州', parent: '浙江省' },
      { name: '嘉兴', parent: '浙江省' },
      { name: '金华', parent: '浙江省' },
      { name: '衢州', parent: '浙江省' },
      { name: '台州', parent: '浙江省' },
      { name: '丽水', parent: '浙江省' },
      { name: '舟山', parent: '浙江省' },

      { name: '黄埔', parent: '上海市' },
      { name: '徐汇', parent: '上海市' },
      { name: '长宁', parent: '上海市' },
      { name: '静安', parent: '上海市' },
    ]
  }
  render() {
    return (
      <div>
        <svg className="zwc"></svg>
      </div>
    );
  }
  componentDidMount() {
    const width = 1026
    const height = 600
    const style = '1px dashed #ccc'

    // const margin = {
    //   top: 30,
    //   right: 30,
    //   bottom: 50,
    //   left: 50
    // }

    // const innerWidth = width - margin.left - margin.right
    // const innerHeight = height - margin.top - margin.bottom
    const innerWidth = width
    const innerHeight = height

    const svg = d3.select('.zwc')
      .attr('width', width)
      .attr('height', height)
      .style('border', style)
    
    const group = svg.append('g')
      .attr('width', innerWidth)
      .attr('height', innerHeight)
      // .attr('transform', `translate(${margin.left}, ${margin.top})`)

    const stratify = d3.stratify()
      .id(d => d.name)
      .parentId(d => d.parent)
    
    const tree = d3.tree()
      .size([1026, 550])
    
    const update = data => {
      group.selectAll('.node')
        .remove()
      
      group.selectAll('.link')
        .remove()
      
      const rootNode = stratify(data)

      const treeData = tree(rootNode)

      const nodes = group.selectAll('.node')
        .data(treeData.descendants())
      
      const enterNode = nodes.enter()
        .append('g')
        .attr('class', 'node')
        .attr('transform', d => `translate(${d.x}, ${d.y})`)
      
      const color = d3.scaleOrdinal(['steelblue', 'orange', 'green'])

      enterNode.append('rect')
        .attr('fill', d => color(d.depth))
        .attr('stroke', '#555')
        .attr('width', d => d.data.name.length * 13)
        .attr('height', 16)
      
      enterNode.append('text')
       .text(d => d.data.name)
       .attr('font-size', '0.8em')
       .attr('dy', '1.1em')
       .attr('dx', '0.2em')
      
      const links = group.selectAll('.link')
        .data(treeData.links())
      
      links.enter()
        .append('path')
        .attr('class', 'link')
        .attr('fill', 'none')
        .attr('stroke', 'pink')
        .attr('stroke-width', '#555')
        .attr('d', d3.linkVertical()
          .x(d => d.x + d.data.name.length * 13 / 2)
          .y(d => d.y + 8)
        )
    }
    update(this.state.data)
  }
}

export default tree;