import React, { Component } from 'react'
import { Menu } from 'antd'
import { BankOutlined, BarChartOutlined, PieChartOutlined, LineChartOutlined, ChromeOutlined, BranchesOutlined } from '@ant-design/icons'
import { withRouter, Switch, Route, Redirect } from 'react-router-dom'

import 'antd/dist/antd.css'
import './App.css'

import Rect from './components/rect'
import Home from './components/home'
import Arc from './components/arc'
import Line from './components/line'
import Circle from './components/circle'
import Tree from './components/tree'

class App extends Component {
  state = {
    current: 'home'
  }
  render() {
    const { current } = this.state
    return (
      <div className="content">
        <Menu onClick={this.handleClick} selectedKeys={[current]} mode="horizontal">
          <Menu.Item key="home" icon={<BankOutlined />}>说明</Menu.Item>
          <Menu.Item key="rect" icon={<BarChartOutlined />}>柱状图</Menu.Item>
          <Menu.Item key="arc" icon={<PieChartOutlined />}>环形图</Menu.Item>
          <Menu.Item key="line" icon={<LineChartOutlined />}>折线图</Menu.Item>
          <Menu.Item key="circle" icon={<ChromeOutlined />}>圆堆图</Menu.Item>
          <Menu.Item key="tree" icon={<BranchesOutlined />}>树形图</Menu.Item>
        </Menu>
        <div className="component">
          <Switch>
            <Route path="/rect" component={ Rect }></Route>
            <Route path="/home" component={ Home }></Route>
            <Route path="/arc" component={ Arc }></Route>
            <Route path="/line" component={ Line }></Route>
            <Route path="/circle" component={ Circle }></Route>
            <Route path="/tree" component={ Tree }></Route>
            <Redirect to="/home"></Redirect>
          </Switch>
        </div>
      </div>
    )
  }
  handleClick = item => {
    const { key } = item
    window.sessionStorage.setItem('key', key)
    this.props.history.push({
      pathname: '/' + key
    })
    this.setState({
      current: key
    })
  }
  componentDidMount() {
    if (window.sessionStorage.getItem('key')) {
      this.setState({
        current: window.sessionStorage.getItem('key')
      })
    } else {
      this.setState({
        current: 'home'
      })
    }
  }
}
export default withRouter(App)