import React, { Component } from 'react';
import * as d3 from 'd3'

class rect extends Component {
  state = {
    data: [
      { year: '2011', value: 7.55 },
      { year: '2012', value: 8.53 },
      { year: '2013', value: 9.57 },
      { year: '2014', value: 10.48 },
      { year: '2015', value: 11.06 },
      { year: '2016', value: 11.23 },
      { year: '2017', value: 12.31 },
      { year: '2018', value: 13.89 },
      { year: '2019', value: 14.34 },
      { year: '2020', value: 15.63 },
    ]
  }
  render() {
    return (
      <div>
        <svg className="zwc"></svg>
      </div>
    );
  }
  componentDidMount() {
    const width = 1026
    const height = 600
    const style = '1px dashed #ccc'

    const margin = {
      top: 30,
      right: 30,
      bottom: 50,
      left: 50
    }

    const innerWidth = width - margin.left - margin.right
    const innerHeight = height - margin.top - margin.bottom

    const svg = d3.select('.zwc')
      .attr('width', width)
      .attr('height', height)
      .style('border', style)
    
    const group = svg.append('g')
      .attr('width', innerWidth)
      .attr('height', innerHeight)
      .attr('transform', `translate(${margin.left}, ${margin.top})`)

    const x = d3.scaleBand()
      .domain(this.state.data.map(d => d.year))
      .range([0, innerWidth])
      .paddingInner(0.2)
      .paddingOuter(.2)
    
    const y = d3.scaleLinear()
      .domain([0, d3.max(this.state.data, d => d.value)])
      .range([innerHeight, 0])

    const xAxis = d3.axisBottom(x)

    const yAxis = d3.axisLeft(y)

    group.append('g')
      .call(xAxis)
      .attr('transform', `translate(0, ${innerHeight})`)
    
    group.append('g')
      .call(yAxis)
    
    const rects = group.selectAll('rect')
      .data(this.state.data)
    
    rects.append('rect')
      .attr('width', x.bandwidth())
      .attr('height', d => innerHeight - y(d.value))
      .attr('x', d => x(d.year))
      .attr('fill', d => d.year % 2 === 0 ? 'green' : 'orange')
    
    rects.enter()
      .append('rect')
      .attr('width', x.bandwidth())
      .attr('height', d => innerHeight - y(d.value))
      .attr('x', d => x(d.year))
      .attr('fill', 'green')
      .attr('y', d => y(d.value))
      .attr('fill', d => d.year % 2 === 0 ? 'green' : 'orange')
    
    group.selectAll('rect')
      .on('mouseenter', (e, data) => {
        d3.select(e.currentTarget)
          .transition('highLight')
          .duration(500)
          .style('opacity', '0.5')
          .style('cursor', 'pointer')
      })
      .on('mouseleave', (e, data) => {
        d3.select(e.currentTarget)
          .transition('highLight')
          .duration(500)
          .style('opacity', '1')
          .style('cursor', 'Auto')
      })
    
    group.append('text')
      .attr('class', 'title')
      .text('中国近十年国内生产总值（GDP）')
      .attr('fill', 'darkblue')
      .attr('transform', `translate(${innerWidth / 2}, 0)`)
      .attr('text-anchor', 'middle')
      .attr('font-size', '1.5em')
    
    group.append('text')
      .attr('class', 'dollar')
      .text('万亿美元')
      .attr('fill', 'blue')
      .attr('transform', `translate(-20, -5)`)
      .attr('text-anchor', 'middle')
      .attr('font-size', '0.8em')
    
    group.append('text')
      .attr('class', 'year')
      .text('年份')
      .attr('fill', 'blue')
      .attr('transform', `translate(${innerWidth}, ${innerHeight + 16})`)
      .attr('text-anchor', 'middle')
      .attr('font-size', '0.8em')
    
    // group.append('text')
    //   .data(this.state.data)
    //   .attr('class', 'data')
    //   .text('年份')
    //   .attr('fill', 'blue')
    //   .attr('transform', `translate(${innerWidth}, ${innerHeight + 16})`)
    //   .attr('text-anchor', 'middle')
    //   .attr('font-size', '0.8em')
    const dataTexts = group.selectAll('.data')
      .data(this.state.data)
    
    dataTexts.append('text')
      // .attr('width', x.bandwidth())
      // .attr('height', d => innerHeight - y(d.value) - 2)
      .attr('x', d => x(d.year))
      .attr('fill', d => d.year % 2 === 0 ? 'green' : 'orange')
      .text(d => d.value)
    
    dataTexts.enter()
      .append('text')
      .attr('class', 'data')
      .attr('width', x.bandwidth())
      .attr('x', d => x(d.year))
      .attr('y', d => y(d.value) - 5)
      .attr('fill', d => d.year % 2 === 0 ? 'green' : 'orange')
      .text(d => d.value)
      .attr('transform', `translate(22, 0)`)
  }
}

export default rect;